@echo off
setlocal enabledelayedexpansion

REM === release.bat ===
REM Copies build output to E:\micronet and backs up existing files first.

set "SRC_BASE=%~dp0"
set "DST_BASE=E:\micronet"
set "BACKUP_BASE=%DST_BASE%\backup"

REM Generate timestamp (YYYYMMDD_HHMMSS)
set "TIMESTAMP=%date:~0,4%%date:~5,2%%date:~8,2%_%time:~0,2%%time:~3,2%%time:~6,2%"
set "TIMESTAMP=%TIMESTAMP: =0%"
set "BACKUP_DIR=%BACKUP_BASE%\%TIMESTAMP%"

echo ============================================
echo  Release Script
echo  Timestamp: %TIMESTAMP%
echo ============================================

REM --- Step 1: Verify source directories exist ---
echo.
echo [Step 1] Verifying source directories...
set "HAS_ERROR=0"

if not exist "%SRC_BASE%Build\Image\exe_test\exe" (
    echo   ERROR: Source not found: %SRC_BASE%Build\Image\exe_test\exe
    set "HAS_ERROR=1"
) else (
    echo   OK: %SRC_BASE%Build\Image\exe_test\exe
)
if not exist "%SRC_BASE%bin" (
    echo   ERROR: Source not found: %SRC_BASE%bin
    set "HAS_ERROR=1"
) else (
    echo   OK: %SRC_BASE%bin
)
if not exist "%SRC_BASE%Build\Image\exe_test\dll" (
    echo   ERROR: Source not found: %SRC_BASE%Build\Image\exe_test\dll
    set "HAS_ERROR=1"
) else (
    echo   OK: %SRC_BASE%Build\Image\exe_test\dll
)
if not exist "%SRC_BASE%Build\Image\exe_test\tool\exe" (
    echo   ERROR: Source not found: %SRC_BASE%Build\Image\exe_test\tool\exe
    set "HAS_ERROR=1"
) else (
    echo   OK: %SRC_BASE%Build\Image\exe_test\tool\exe
)

if "%HAS_ERROR%"=="1" (
    echo.
    echo Aborted: one or more source directories are missing.
    exit /b 1
)

REM --- Step 2: Backup existing destination folders ---
echo.
echo [Step 2] Backing up to %BACKUP_DIR% ...
mkdir "%BACKUP_DIR%" 2>nul

if exist "%DST_BASE%\exe" (
    echo   Backing up exe ...
    robocopy "%DST_BASE%\exe" "%BACKUP_DIR%\exe" /E /NFL /NDL /NJH /NJS /NC /NS >nul 2>&1
)
if exist "%DST_BASE%\bin" (
    echo   Backing up bin ...
    robocopy "%DST_BASE%\bin" "%BACKUP_DIR%\bin" /E /NFL /NDL /NJH /NJS /NC /NS >nul 2>&1
)
if exist "%DST_BASE%\dll" (
    echo   Backing up dll ...
    robocopy "%DST_BASE%\dll" "%BACKUP_DIR%\dll" /E /NFL /NDL /NJH /NJS /NC /NS >nul 2>&1
)
if exist "%DST_BASE%\tool\exe" (
    echo   Backing up tool\exe ...
    robocopy "%DST_BASE%\tool\exe" "%BACKUP_DIR%\tool\exe" /E /NFL /NDL /NJH /NJS /NC /NS >nul 2>&1
)
echo   Backup complete.

REM --- Step 3: Copy build output to destination ---
echo.
echo [Step 3] Copying build output...
set "COPY_ERROR=0"

echo   exe ...
robocopy "%SRC_BASE%Build\Image\exe_test\exe" "%DST_BASE%\exe" /E /NFL /NDL /NJH /NJS /NC /NS
if !errorlevel! GEQ 8 (
    echo   ERROR: Failed to copy exe
    set "COPY_ERROR=1"
)

echo   bin ...
robocopy "%SRC_BASE%bin" "%DST_BASE%\bin" /E /NFL /NDL /NJH /NJS /NC /NS
if !errorlevel! GEQ 8 (
    echo   ERROR: Failed to copy bin
    set "COPY_ERROR=1"
)

echo   dll ...
robocopy "%SRC_BASE%Build\Image\exe_test\dll" "%DST_BASE%\dll" /E /NFL /NDL /NJH /NJS /NC /NS
if !errorlevel! GEQ 8 (
    echo   ERROR: Failed to copy dll
    set "COPY_ERROR=1"
)

echo   tool\exe ...
robocopy "%SRC_BASE%Build\Image\exe_test\tool\exe" "%DST_BASE%\tool\exe" /E /NFL /NDL /NJH /NJS /NC /NS
if !errorlevel! GEQ 8 (
    echo   ERROR: Failed to copy tool\exe
    set "COPY_ERROR=1"
)

echo.
if "%COPY_ERROR%"=="1" (
    echo [RESULT] Completed with errors. Check the output above.
    exit /b 1
) else (
    echo [RESULT] Release completed successfully.
    echo   Backup: %BACKUP_DIR%
)

endlocal
exit /b 0

